css.web:
.license-text {
  font-size: 0.9em;
}

a.header-link {
  font-weight: inherit !important;
  font-size: inherit !important;
  color: #000000;
  text-decoration: none;
}

a.header-link:hover::after {
  content: '#';
  padding-left: 5px;
  color: blue;
  display: inline-block;
}

/* ─── Compact study-Bible layout ──────────────────────────
   Scripture and Translation Words render as parallel columns
   (one per aligned Bible, e.g. ULT | UST). */

table.tn-scripture-cols,
table.tn-verse-twl-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
  margin: 4px 0 8px 0;
  font-size: 0.95em;
}

.tn-col-label {
  text-align: left;
  font-size: 0.72em;
  font-weight: bold;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: #555;
  border-bottom: 1px solid #ccc;
  padding: 1px 6px;
}

table.tn-scripture-cols td,
table.tn-verse-twl-table td {
  vertical-align: top;
  padding: 3px 6px;
  border-right: 1px solid #eee;
}

table.tn-scripture-cols td:last-child,
table.tn-verse-twl-table td:last-child {
  border-right: none;
}

table.tn-scripture-cols {
  background-color: #f9f9f9;
  border: 1px solid #ddd;
}

td.tn-scripture-text {
  font-style: italic;
}

.tn-verse-twl-header {
  font-size: 0.85em;
  font-weight: bold;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: #555;
  margin: 8px 0 1px 0;
}

.tn-verse-twl-table a {
  text-decoration: none;
}

/* Notes — compact, with a per-Bible quote line and a small Bible tag. */
.tn-note-header {
  font-size: 0.95em;
  margin: 5px 0 1px 0;
  padding: 2px 8px;
  background-color: #f1f1f1;
  border-left: 3px solid #ccc;
}

.tn-note-quote {
  line-height: 1.35;
}

.tn-bible-tag {
  display: inline-block;
  font-size: 0.68em;
  font-weight: bold;
  color: #fff;
  background-color: #8a8a8a;
  border-radius: 3px;
  padding: 0 4px;
  margin-right: 4px;
  vertical-align: middle;
}

.tn-note-orig {
  font-size: 0.85em;
  color: #666;
}

.tn-note-body {
  padding: 2px 0;
}

.tn-note-support-reference {
  font-size: 0.8em;
  color: #555;
  margin: 1px 0 0 0;
}

.tn-note-label {
  font-weight: bold;
}

hr.note-divider {
  border: none;
  border-top: 1px solid #eee;
  margin: 4px 0;
}

.appendix-header {
  text-align: center;
}

.appendix-article {
  margin-bottom: 16px;
}

.appendix-article-body h1,
.appendix-article-body h2,
.appendix-article-body h3,
.appendix-article-body h4 {
  font-size: 1em;
}

.back-refs {
  margin-top: 8px;
  font-size: 0.9em;
}

.back-refs a {
  margin-right: 8px;
}

.header-title {
  display: block;
  margin-bottom: 0.5rem;
  color: #666;
  font-size: 0.85em;
}

.cover-page {
  text-align: center;
  padding-top: 2rem;
}

.cover-page .header-title {
  display: none;
}

.cover-page .title-logo {
  display: block;
  margin: 0 auto 1rem auto;
  width: 180px;
  max-width: 60%;
  height: auto;
}

.cover-page .cover-header,
.cover-page .cover-version,
.cover-page .cover-book-title,
.cover-page .cover-resource-title {
  text-align: center;
  margin-left: auto;
  margin-right: auto;
}

.cover-page .cover-version {
  color: #666;
  font-weight: normal;
}

css.print:
.tn-book-header {
  break-after: avoid !important;
}

.tn-chapter-header {
  break-after: avoid !important;
}

.tn-verse-header {
  break-after: avoid !important;
}

.tn-scripture-block {
  break-inside: avoid;
}

article.tn-note {
  break-inside: avoid;
  orphans: 2;
  widows: 2;
}

hr {
  break-before: avoid !important;
}

.appendix-article {
  break-after: page !important;
}
